Material.Shader:
/*
 */

varying float scalar;

void main(void)
{

  vec3 lightDirection = normalize((gl_ModelViewMatrixInverse * gl_LightSource[0].position).xyz - gl_Vertex.xyz);// locate space
  scalar = dot(normalize(lightDirection),gl_Normal); // range [-1 1]
  scalar = (scalar + 1.0) * 6.0; // range [0 12]

  gl_Position = ftransform();
}



/*
 */

varying float scalar;

uniform vec4 Color0;
uniform vec4 Color1;

void main(void)
{
	int parity = scalar;

	if(scalar == 0.0)
	{
		gl_FragColor = vec4(1.0, 1.0, 0.0, 1.0);
	}
	else if( scalar > 11.9)
	{
		gl_FragColor = vec4(1.0, 0.0, 1.0, 1.0);
	}
	else 
	{
		if((parity % 2) == 0)
			gl_FragColor = Color1;
		else
			gl_FragColor = Color0;
	}
}
